Create the EventFanOut service at `apps/server/src/services/core/event-fan-out.ts`. This is a lightweight in-process broadcaster that manages a Set of SSE Response objects and distributes events to all connected clients.

## Implementation

Create the file with the following complete implementation:

```typescript
// apps/server/src/services/core/event-fan-out.ts
import type { Response } from 'express';
import { SSE } from '../../config/constants.js';
import { logger } from '../../lib/logger.js';

/**
 * In-process event fan-out broadcaster for the unified SSE stream.
 *
 * Manages a set of connected SSE clients and distributes events to all of them.
 * Uses the SSE spec's `event:` field for type routing — clients filter by event name.
 */
class EventFanOut {
  private clients = new Set<Response>();

  /** Register an SSE client. Returns an unsubscribe function. */
  addClient(res: Response): () => void {
    if (this.clients.size >= SSE.MAX_TOTAL_CLIENTS) {
      logger.warn(`[EventFanOut] Max clients reached (${SSE.MAX_TOTAL_CLIENTS}), rejecting`);
      res.status(503).json({ error: 'Too many SSE clients' });
      return () => {};
    }

    this.clients.add(res);

    return () => {
      this.clients.delete(res);
    };
  }

  /** Broadcast an SSE event to all connected clients. */
  broadcast(eventName: string, data: unknown): void {
    const payload = `event: ${eventName}\ndata: ${JSON.stringify(data)}\n\n`;

    for (const client of this.clients) {
      if (client.writableEnded) {
        this.clients.delete(client);
        continue;
      }
      try {
        const canContinue = client.write(payload);
        if (!canContinue) {
          // Backpressure: skip events for this client until drained.
          // The client will catch up via query invalidation on reconnect.
          client.once('drain', () => {
            // Resume is implicit — next broadcast will succeed
          });
        }
      } catch {
        this.clients.delete(client);
      }
    }
  }

  /** Number of currently connected clients. */
  get clientCount(): number {
    return this.clients.size;
  }
}

export const eventFanOut = new EventFanOut();
```

Key behaviors:
- `addClient` enforces `SSE.MAX_TOTAL_CLIENTS` (500) limit, returns 503 when exceeded
- `broadcast` writes SSE-formatted payloads using the `event:` field for type routing
- `broadcast` prunes clients with `writableEnded === true` defensively
- `broadcast` handles `res.write()` throwing by removing the client
- `broadcast` handles backpressure (`res.write()` returns false) by registering a drain listener
- The class is exported as a singleton instance `eventFanOut`

The `SSE.MAX_TOTAL_CLIENTS` constant already exists in `apps/server/src/config/constants.ts` (value: 500).

## Unit Tests

Create `apps/server/src/services/core/__tests__/event-fan-out.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';

// Must mock before importing the module under test
vi.mock('../../../config/constants.js', () => ({
  SSE: { MAX_TOTAL_CLIENTS: 3 },
}));
vi.mock('../../../lib/logger.js', () => ({
  logger: { warn: vi.fn(), info: vi.fn(), error: vi.fn() },
}));

import { eventFanOut } from '../event-fan-out.js';

function mockResponse(overrides: Partial<Record<string, unknown>> = {}) {
  return {
    writableEnded: false,
    write: vi.fn().mockReturnValue(true),
    status: vi.fn().mockReturnThis(),
    json: vi.fn(),
    once: vi.fn(),
    ...overrides,
  } as unknown as import('express').Response;
}

describe('EventFanOut', () => {
  beforeEach(() => {
    // Reset the clients set between tests by removing all
    while (eventFanOut.clientCount > 0) {
      // We can't directly access private clients, so we rely on the tests
      // being self-contained (each adds and removes its own clients)
    }
  });

  it('addClient registers a response and broadcast writes to it', () => {
    const res = mockResponse();
    const unsub = eventFanOut.addClient(res);

    eventFanOut.broadcast('tunnel_status', { connected: true });

    expect(res.write).toHaveBeenCalledWith(
      'event: tunnel_status\ndata: {"connected":true}\n\n'
    );

    unsub();
  });

  it('addClient rejects when MAX_TOTAL_CLIENTS is reached (returns 503)', () => {
    const clients = Array.from({ length: 3 }, () => mockResponse());
    const unsubs = clients.map((c) => eventFanOut.addClient(c));

    const overflow = mockResponse();
    eventFanOut.addClient(overflow);

    expect(overflow.status).toHaveBeenCalledWith(503);
    expect(overflow.json).toHaveBeenCalledWith({ error: 'Too many SSE clients' });

    unsubs.forEach((u) => u());
  });

  it('broadcast removes clients whose writableEnded is true', () => {
    const res = mockResponse({ writableEnded: true });
    eventFanOut.addClient(res);

    eventFanOut.broadcast('test', {});

    expect(res.write).not.toHaveBeenCalled();
  });

  it('broadcast handles res.write() throwing (removes client)', () => {
    const res = mockResponse({
      write: vi.fn().mockImplementation(() => { throw new Error('broken pipe'); }),
    });
    const unsub = eventFanOut.addClient(res);

    // Should not throw
    expect(() => eventFanOut.broadcast('test', {})).not.toThrow();

    unsub();
  });

  it('broadcast handles backpressure (res.write returns false)', () => {
    const res = mockResponse({ write: vi.fn().mockReturnValue(false) });
    const unsub = eventFanOut.addClient(res);

    eventFanOut.broadcast('test', { data: 'payload' });

    expect(res.once).toHaveBeenCalledWith('drain', expect.any(Function));

    unsub();
  });

  it('clientCount reflects add/remove operations', () => {
    const res1 = mockResponse();
    const res2 = mockResponse();

    const unsub1 = eventFanOut.addClient(res1);
    expect(eventFanOut.clientCount).toBe(1);

    const unsub2 = eventFanOut.addClient(res2);
    expect(eventFanOut.clientCount).toBe(2);

    unsub1();
    expect(eventFanOut.clientCount).toBe(1);

    unsub2();
    expect(eventFanOut.clientCount).toBe(0);
  });
});
```

## Acceptance Criteria
- `EventFanOut` class exists at `apps/server/src/services/core/event-fan-out.ts`
- Singleton `eventFanOut` is exported
- `addClient` enforces the MAX_TOTAL_CLIENTS limit with 503 response
- `broadcast` writes SSE-formatted events with `event:` and `data:` fields
- `broadcast` handles dead clients, throwing clients, and backpressure
- All 6 unit tests pass

Create the unified SSE endpoint at `apps/server/src/routes/events.ts` and mount it in the Express app. This endpoint replaces the 3 individual SSE endpoints (tunnel, extensions, relay) with a single stream.

## Implementation

Create `apps/server/src/routes/events.ts`:

```typescript
// apps/server/src/routes/events.ts
import { Router } from 'express';
import { initSSEStream } from '../services/core/stream-adapter.js';
import { SSE } from '../config/constants.js';
import { eventFanOut } from '../services/core/event-fan-out.js';

const router = Router();

/**
 * GET /api/events — unified SSE endpoint for all global event streams.
 *
 * Consolidates tunnel status, extension lifecycle, and relay events into a single
 * Server-Sent Events connection. Uses the SSE spec's `event:` field for type routing.
 * The session sync stream (GET /api/sessions/:id/stream) stays separate.
 */
router.get('/', (req, res) => {
  initSSEStream(res);

  // Register this client with the fan-out service
  const unsubscribe = eventFanOut.addClient(res);

  // Send initial connection confirmation
  res.write(
    `event: connected\ndata: ${JSON.stringify({ connectedAt: new Date().toISOString() })}\n\n`
  );

  // Shared heartbeat at server interval
  const keepalive = setInterval(() => {
    if (res.writableEnded) {
      clearInterval(keepalive);
      return;
    }
    try {
      res.write(`: keepalive\n\n`);
    } catch {
      clearInterval(keepalive);
    }
  }, SSE.HEARTBEAT_INTERVAL_MS);

  req.on('close', () => {
    clearInterval(keepalive);
    unsubscribe();
  });
});

export default router;
```

Mount the route in `apps/server/src/app.ts`. Add the import at the top with other route imports:

```typescript
import eventsRouter from './routes/events.js';
```

Add the route mount after the existing API routes (around line 123, after `app.use('/api/mcp-config', mcpConfigRoutes)`):

```typescript
app.use('/api/events', eventsRouter);
```

Key behaviors:
- Uses `initSSEStream` from `stream-adapter.ts` for standardized SSE headers (`Content-Type: text/event-stream`, `Cache-Control: no-cache`, `Connection: keep-alive`, `X-Accel-Buffering: no`)
- Sends `connected` event immediately on connection so the client can confirm the stream is alive
- Heartbeat comment (`: keepalive\n\n`) fires every 15s using `SSE.HEARTBEAT_INTERVAL_MS`
- Client cleanup on disconnect: clears heartbeat interval and unsubscribes from fan-out
- Client count is bounded by `SSE.MAX_TOTAL_CLIENTS` (enforced in EventFanOut.addClient)

## Integration Tests

Create `apps/server/src/routes/__tests__/events.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import express from 'express';
import request from 'supertest';

vi.mock('../../services/core/event-fan-out.js', () => ({
  eventFanOut: {
    addClient: vi.fn().mockReturnValue(() => {}),
    broadcast: vi.fn(),
    get clientCount() { return 0; },
  },
}));

import eventsRouter from '../events.js';
import { eventFanOut } from '../../services/core/event-fan-out.js';

const app = express();
app.use('/api/events', eventsRouter);

describe('GET /api/events', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('returns SSE headers', async () => {
    const res = await request(app)
      .get('/api/events')
      .buffer(true)
      .parse((res, callback) => {
        let data = '';
        res.on('data', (chunk: Buffer) => {
          data += chunk.toString();
          // Close after getting the connected event
          if (data.includes('connected')) {
            res.destroy();
          }
        });
        res.on('end', () => callback(null, data));
        res.on('error', () => callback(null, data));
      });

    expect(res.headers['content-type']).toBe('text/event-stream');
    expect(res.headers['cache-control']).toBe('no-cache');
    expect(res.headers['connection']).toBe('keep-alive');
  });

  it('sends connected event on connection', async () => {
    const res = await request(app)
      .get('/api/events')
      .buffer(true)
      .parse((res, callback) => {
        let data = '';
        res.on('data', (chunk: Buffer) => {
          data += chunk.toString();
          if (data.includes('connectedAt')) {
            res.destroy();
          }
        });
        res.on('end', () => callback(null, data));
        res.on('error', () => callback(null, data));
      });

    expect(res.body).toContain('event: connected');
    expect(res.body).toContain('connectedAt');
  });

  it('registers client with eventFanOut', async () => {
    await request(app)
      .get('/api/events')
      .buffer(true)
      .parse((res, callback) => {
        let data = '';
        res.on('data', (chunk: Buffer) => {
          data += chunk.toString();
          if (data.includes('connected')) res.destroy();
        });
        res.on('end', () => callback(null, data));
        res.on('error', () => callback(null, data));
      });

    expect(eventFanOut.addClient).toHaveBeenCalled();
  });
});
```

## Acceptance Criteria
- `GET /api/events` endpoint exists and returns `text/event-stream` headers
- Client receives `event: connected` with `connectedAt` timestamp on connection
- Heartbeat comment fires every 15s
- Client is registered with `eventFanOut.addClient` and unregistered on disconnect
- Route is mounted in `app.ts` at `/api/events`
- Integration tests pass

Wire the three existing event sources (tunnel manager, extension broadcaster, relay core) to the new `eventFanOut.broadcast()` service. This makes events from all three sources flow through the unified `/api/events` endpoint.

## 1. Tunnel Events

In `apps/server/src/index.ts`, after the `tunnelManager` import (already at line 5), add the fan-out wiring. The tunnel manager is a module-level singleton, so this can be wired at server startup.

Add import at the top of `index.ts`:
```typescript
import { eventFanOut } from './services/core/event-fan-out.js';
```

Add wiring after the app is created (before the service initialization block, or inside the startup function). The tunnel manager is always available (not behind a feature flag):

```typescript
// Tunnel status changes -> unified SSE stream
tunnelManager.on('status_change', (status: TunnelStatus) => {
  eventFanOut.broadcast('tunnel_status', status);
});
```

Note: The existing `/api/tunnel/stream` endpoint sends current status immediately on connection (line 48 of `tunnel.ts`). The unified stream does NOT replicate this — the client fetches `GET /api/tunnel/status` on mount (via `useTunnelStatus` query) and the SSE stream only pushes subsequent changes. This avoids sending domain-specific initial state from a generic endpoint.

## 2. Extension Events

Modify `apps/server/src/routes/extensions.ts` to use `eventFanOut.broadcast()` instead of the module-level `sseClients` Set.

Add import:
```typescript
import { eventFanOut } from '../services/core/event-fan-out.js';
```

Replace the `broadcastExtensionReloaded` function body (keep the same export signature so callers like `extension-tools.ts` are unaffected):

```typescript
/**
 * Broadcast an `extension_reloaded` event to all connected SSE clients.
 * Only call this after at least one extension has compiled successfully.
 *
 * @param extensionIds - IDs of the extensions that were reloaded
 */
export function broadcastExtensionReloaded(extensionIds: string[]): void {
  eventFanOut.broadcast('extension_reloaded', {
    type: 'extension_reloaded',
    extensionIds,
    timestamp: Date.now(),
  });
}
```

The module-level `sseClients` Set (line 15) and the `GET /events` handler (lines 62-79) remain for now — they will get deprecation markers in Phase D. The `broadcastExtensionReloaded` function now writes to both the old endpoint (via the sseClients Set that remains in the GET handler) and the unified stream (via eventFanOut). Wait — actually, with this change, `broadcastExtensionReloaded` ONLY writes to `eventFanOut`, not to the old `sseClients` Set. The old `GET /events` handler still adds to `sseClients`, but nobody calls the old broadcast logic anymore. This is correct: once clients migrate to `/api/events`, the old endpoint still works (clients can connect) but won't receive events until they're wired. Since we're migrating clients in Phase C, this is a transitional state. To keep the old endpoint working during the transition, we should broadcast to BOTH:

```typescript
export function broadcastExtensionReloaded(extensionIds: string[]): void {
  const data = JSON.stringify({
    type: 'extension_reloaded',
    extensionIds,
    timestamp: Date.now(),
  });

  // Broadcast to unified stream
  eventFanOut.broadcast('extension_reloaded', {
    type: 'extension_reloaded',
    extensionIds,
    timestamp: Date.now(),
  });

  // Backward compat: also broadcast to old SSE clients (deprecated endpoint)
  for (const client of sseClients) {
    try {
      client.write(`event: extension_reloaded\ndata: ${data}\n\n`);
    } catch {
      sseClients.delete(client);
    }
  }
}
```

This ensures the old `/api/extensions/events` endpoint still works during the transition period.

## 3. Relay Events

In `apps/server/src/index.ts`, inside the existing relay-enabled block (around line 314-323), add fan-out wiring after `relayCore` is confirmed available:

```typescript
// Mount Relay routes if enabled
if (relayEnabled && relayCore) {
  app.use('/api/relay', createRelayRouter(relayCore, adapterManager, traceStore));
  setRelayEnabled(true);

  // Store relayCore on app.locals so the sessions router can access it
  app.locals.relayCore = relayCore;

  // Wire relay events to unified SSE stream
  const unsubMessages = relayCore.subscribe('relay.human.console.>', (envelope) => {
    eventFanOut.broadcast('relay_message', envelope);
  });

  const unsubSignals = relayCore.onSignal('relay.human.console.>', (_subject, signal) => {
    const eventType = signal.type === 'backpressure' ? 'relay_backpressure' : 'relay_signal';
    eventFanOut.broadcast(eventType, signal);
  });

  // Send initial relay connection event
  eventFanOut.broadcast('relay_connected', {
    pattern: 'relay.human.console.>',
    connectedAt: new Date().toISOString(),
  });

  logger.info('[Relay] Routes mounted');
}
```

Note: The unified stream always subscribes to `relay.human.console.>` (the default pattern the web client uses). External adapters needing custom `?subject=` filtering should continue using `GET /api/relay/stream` directly.

## Verification

After wiring all three sources:
1. Start the dev server (`pnpm dev`)
2. Open `http://localhost:6242/api/events` in a browser directly
3. Toggle tunnel on/off — confirm `event: tunnel_status` events appear
4. Trigger an extension reload — confirm `event: extension_reloaded` events appear
5. If relay is enabled, confirm `event: relay_connected` appears in the stream

## Acceptance Criteria
- Tunnel status changes produce `event: tunnel_status` on the unified stream
- Extension reloads produce `event: extension_reloaded` on the unified stream (and still work on the old endpoint)
- Relay messages produce `event: relay_message` on the unified stream
- Relay signals produce `event: relay_backpressure` or `event: relay_signal` on the unified stream
- The `broadcastExtensionReloaded` function signature is unchanged (callers in `extension-tools.ts` unaffected)
- The existing `GET /api/relay/stream` endpoint is unaffected (still works for external adapters)

Create a React context provider at the shared layer that manages the single `SSEConnection` to `/api/events` and exposes a subscription API for consumers.

## Implementation

Create `apps/client/src/layers/shared/model/event-stream-context.tsx`:

```typescript
// apps/client/src/layers/shared/model/event-stream-context.tsx
import { createContext, useContext, useEffect, useRef, useState, useCallback, type ReactNode } from 'react';
import type { ConnectionState } from '@dorkos/shared/types';
import { SSEConnection } from '@/layers/shared/lib/transport';

type EventHandler = (data: unknown) => void;
type Unsubscribe = () => void;

/** Context value for the global unified event stream. */
interface EventStreamContextValue {
  /** Subscribe to a specific SSE event type. Returns an unsubscribe function. */
  subscribe: (eventName: string, handler: EventHandler) => Unsubscribe;
  /** Current connection state of the unified stream. */
  connectionState: ConnectionState;
  /** Number of consecutive failed connection attempts. */
  failedAttempts: number;
}

const EventStreamContext = createContext<EventStreamContextValue | null>(null);

/**
 * Provider that manages the single SSEConnection to `/api/events`.
 *
 * Creates one `SSEConnection` on mount that persists for the app lifetime.
 * Consumers subscribe to specific event types via `useEventSubscription`.
 *
 * Must mount before `ExtensionProvider` in the provider tree because
 * the extension context subscribes to `extension_reloaded` events.
 *
 * Provider tree placement in main.tsx:
 *   QueryClientProvider
 *     -> TransportProvider
 *       -> EventStreamProvider        <- HERE
 *         -> ExtensionProvider
 *           -> PasscodeGateWrapper
 *             -> RouterProvider
 */
export function EventStreamProvider({ children }: { children: ReactNode }) {
  const [connectionState, setConnectionState] = useState<ConnectionState>('connecting');
  const [failedAttempts, setFailedAttempts] = useState(0);
  const connectionRef = useRef<SSEConnection | null>(null);
  const listenersRef = useRef(new Map<string, Set<EventHandler>>());

  // Initialize the SSEConnection once on mount
  useEffect(() => {
    // All event names from the unified stream's event name registry.
    // Must stay in sync with the server's EventFanOut sources.
    // If a new event type is added server-side, add it here too.
    const knownEvents = [
      'connected',
      'tunnel_status',
      'extension_reloaded',
      'relay_connected',
      'relay_message',
      'relay_backpressure',
      'relay_signal',
    ];

    const eventHandlers: Record<string, (data: unknown) => void> = {};
    for (const eventName of knownEvents) {
      eventHandlers[eventName] = (data: unknown) => {
        const handlers = listenersRef.current.get(eventName);
        if (handlers) {
          for (const handler of handlers) {
            try {
              handler(data);
            } catch {
              // Consumer error should not break the stream
            }
          }
        }
      };
    }

    const connection = new SSEConnection('/api/events', {
      eventHandlers,
      onStateChange: (state, attempts) => {
        setConnectionState(state);
        setFailedAttempts(attempts);
      },
    });

    connection.connect();
    connection.enableVisibilityOptimization();
    connectionRef.current = connection;

    return () => {
      connection.destroy();
      connectionRef.current = null;
    };
  }, []);

  const subscribe = useCallback((eventName: string, handler: EventHandler): Unsubscribe => {
    if (!listenersRef.current.has(eventName)) {
      listenersRef.current.set(eventName, new Set());
    }
    listenersRef.current.get(eventName)!.add(handler);

    return () => {
      const handlers = listenersRef.current.get(eventName);
      if (handlers) {
        handlers.delete(handler);
        if (handlers.size === 0) {
          listenersRef.current.delete(eventName);
        }
      }
    };
  }, []);

  return (
    <EventStreamContext.Provider value={{ subscribe, connectionState, failedAttempts }}>
      {children}
    </EventStreamContext.Provider>
  );
}

/** Access the global event stream subscription API. */
export function useEventStream(): EventStreamContextValue {
  const ctx = useContext(EventStreamContext);
  if (!ctx) {
    throw new Error('useEventStream must be used within an EventStreamProvider');
  }
  return ctx;
}

/**
 * Subscribe to a specific event type from the unified stream.
 * The handler is ref-stabilized to prevent re-subscriptions on identity changes.
 */
export function useEventSubscription(eventName: string, handler: EventHandler): void {
  const { subscribe } = useEventStream();
  const handlerRef = useRef(handler);
  handlerRef.current = handler;

  useEffect(() => {
    return subscribe(eventName, (data) => handlerRef.current(data));
  }, [subscribe, eventName]);
}
```

