import { renderHook, act, cleanup } from '@testing-library/react';
import type { ReactNode } from 'react';

// Mock SSEConnection
const mockConnect = vi.fn();
const mockDestroy = vi.fn();
const mockEnableVisibility = vi.fn();
let capturedEventHandlers: Record<string, (data: unknown) => void> = {};
let capturedOnStateChange: ((state: string, attempts: number) => void) | undefined;

vi.mock('@/layers/shared/lib/transport', () => ({
  SSEConnection: vi.fn().mockImplementation((_url: string, options: { eventHandlers: Record<string, (data: unknown) => void>; onStateChange?: (state: string, attempts: number) => void }) => {
    capturedEventHandlers = options.eventHandlers;
    capturedOnStateChange = options.onStateChange;
    return {
      connect: mockConnect,
      destroy: mockDestroy,
      enableVisibilityOptimization: mockEnableVisibility,
    };
  }),
}));

import { EventStreamProvider, useEventStream, useEventSubscription } from '../event-stream-context';

function Wrapper({ children }: { children: ReactNode }) {
  return <EventStreamProvider>{children}</EventStreamProvider>;
}

beforeEach(() => {
  vi.clearAllMocks();
  capturedEventHandlers = {};
  capturedOnStateChange = undefined;
});

afterEach(cleanup);

describe('EventStreamProvider', () => {
  it('creates SSEConnection on mount', () => {
    renderHook(() => useEventStream(), { wrapper: Wrapper });
    expect(mockConnect).toHaveBeenCalledOnce();
    expect(mockEnableVisibility).toHaveBeenCalledOnce();
  });

  it('destroys SSEConnection on unmount', () => {
    const { unmount } = renderHook(() => useEventStream(), { wrapper: Wrapper });
    unmount();
    expect(mockDestroy).toHaveBeenCalledOnce();
  });
});

describe('useEventStream', () => {
  it('throws outside provider', () => {
    expect(() => {
      renderHook(() => useEventStream());
    }).toThrow('useEventStream must be used within an EventStreamProvider');
